#include <stdio.h>
#include <stdlib.h>

// Structure for adjacency list
typedef struct AdjListNode {
    int vertex;
    struct AdjListNode* next;
} AdjListNode;

// Structure for graph
typedef struct Graph {
    int numVertices;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int vertex) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with given vertices
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error
");
        return NULL;
    }

    graph->numVertices = vertices;

    // Create an array to hold the adjacency lists
    graph->adjLists = (AdjListNode**) malloc(vertices * sizeof(AdjListNode*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = NULL;
    }

    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    // Add edge to the source node
    AdjListNode* newNode = createNode(dest);
    if (graph->adjLists[src] == NULL) {
        graph->adjLists[src] = newNode;
    } else {
        AdjListNode* lastNode = graph->adjLists[src];
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to detect cycle in a directed graph using DFS
int isCyclicUtil(Graph* graph, int vertex, int* visited, int* recursionStack) {
    if (recursionStack[vertex]) {
        return 1;
    }

    if (visited[vertex]) {
        return 0;
    }

    visited[vertex] = 1;
    recursionStack[vertex] = 1;

    AdjListNode* node = graph->adjLists[vertex];
    while (node) {
        int adjacentVertex = node->vertex;
        if (isCyclicUtil(graph, adjacentVertex, visited, recursionStack)) {
            return 1;
        }
        node = node->next;
    }

    recursionStack[vertex] = 0;
    return 0;
}

// Function to detect cycle in a directed graph
int isCyclic(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* recursionStack = (int*) malloc(graph->numVertices * sizeof(int));

    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
        recursionStack[i] = 0;
    }

    for (int i = 0; i < graph->numVertices; i++) {
        if (isCyclicUtil(graph, i, visited, recursionStack)) {
            free(visited);
            free(recursionStack);
            return 1;
        }
    }

    free(visited);
    free(recursionStack);
    return 0;
}

