from typing import List

class Solution:
    def isCyclicUtil(self, node: int, adj: List[List[int]], visited: List[bool], recursionStack: List[bool]) -> bool:
        visited[node] = True
        recursionStack[node] = True

        for neighbor in adj[node]:
            if not visited[neighbor]:
                if self.isCyclicUtil(neighbor, adj, visited, recursionStack):
                    return True
            elif recursionStack[neighbor]:
                return True

        recursionStack[node] = False
        return False

    def isCyclic(self, V: int, adj: List[List[int]]) -> bool:
        visited = [False] * V
        recursionStack = [False] * V

        for i in range(V):
            if not visited[i]:
                if self.isCyclicUtil(i, adj, visited, recursionStack):
                    return True
        return False

