        visited[node] = true;
        recursionStack[node] = true;

        for (let neighbor of adj[node]) {
            if (!visited[neighbor]) {
                if (this.isCyclicUtil(neighbor, adj, visited, recursionStack)) {
                    return true;
                }
            } else if (recursionStack[neighbor]) {
                return true;
            }
        }

        recursionStack[node] = false;
        return false;
    }

