        let visited = new Array(V).fill(false);
        let recursionStack = new Array(V).fill(false);

        for (let i = 0; i < V; i++) {
            if (!visited[i]) {
                if (this.isCyclicUtil(i, adj, visited, recursionStack)) {
                    return true;
                }
            }
        }
        return false;
    }
}

